import { CrmProvider } from '../context/CrmProvider.jsx'
import { mockXrm } from './mock-xrm.js'

/**
 * Versión mock de CrmProvider para uso en desarrollo local.
 * Inyecta el mockXrm sin necesidad de Dynamics 365.
 *
 * Uso: Envuelve tu app con este provider en main.jsx cuando import.meta.env.DEV === true
 */
export const MockCrmProvider = ({ children, xrmOverride = mockXrm }) => {
  return <CrmProvider xrmOverride={xrmOverride}>{children}</CrmProvider>
}
